example.code:
experiment_id: checkout-v2-button-color
hypothesis: high-contrast blue increases checkout conversion
primary_metric: {name: checkout_conversion_rate, delta_direction: increase}
guardrails:
  - {name: p95_latency_ms, floor: <=250}
  - {name: error_rate, floor: <=0.005}
  - {name: revenue_per_user, floor: '>=baseline'}
mde: {effect_size: +2pp, sample_size: 24000, runtime_days: 14}
srm_passed: true
result: +2.4pp primary; all guardrails green
decision: ship
